    round_code: 'c',
    raised_amount: 1000000,
    raised_currency_code: 'USD'
  },
  {
    round_code: 'seed',
    raised_amount: 1000000,
    raised_currency_code: 'USD'
  },
  {
    round_code: 'a',
    raised_amount: 1000000,
